const path = require('path');
const fs = require('fs');

const problemsFile = path.resolve(__dirname, '../../data/problems.json');

let problemsData = null;

function loadProblemsData() {
  if (!problemsData) {
    const raw = fs.readFileSync(problemsFile, 'utf8');
    problemsData = JSON.parse(raw);
  }
  return problemsData;
}

/**
 * Get detailed problem info by problemId including component statistics.
 * @param {string} problemId
 * @returns {object|null} problem detail with aggregated component stats or null if not found
 */
async function getProblemDetail(problemId) {
  const problems = loadProblemsData();
  const problem = problems.find(p => p.problemId === problemId);
  if (!problem) return null;

  // Aggregate component statistics
  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  if (problem.components && Array.isArray(problem.components)) {
    for (const comp of problem.components) {
      if (comp.language) {
        languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
      }
      if (comp.status) {
        statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
      }
      if (typeof comp.points === 'number' && comp.points > maxPoints) {
        maxPoints = comp.points;
      }
    }
  }

  return {
    ...problem,
    componentStats: {
      languageCounts,
      statusCounts,
      maxPoints,
    },
  };
}

module.exports = {
  getProblemDetail,
};
